const fn jc_p0(b: u8) -> bool {
    match b {
        _ => false,
    }
}

#[cfg(feature = "bmp")]
const fn jc_p20(b: u8) -> bool {
    match b {
        0x0c..=0x0d => true,
        _ => false,
    }
}
